import { CardRank, HandType, HandRange, CARD_RANKS, RANK_ORDER } from './types';

// 169 starting hands bucketed by cumulative top-X% strength. Generated by
// scripts/gen-hand-rankings.mjs from a seeded (mulberry32(42)) Monte Carlo
// simulation of each hand's equity vs a uniformly random opponent hand on a
// uniformly random 5-card board (300k trials/hand), ranked descending and
// bucketed by walking cumulative combo counts (pair=6, suited=4, offsuit=12)
// against fixed target boundaries. Re-run the script to reproduce.
// Each bucket label corresponds to its cumulative threshold; empty bucket falls through to '60-70%'.
