  'T9s':'40-45%','33':'40-45%','Q6s':'40-45%','Q8o':'40-45%','J9o':'40-45%','K5o':'40-45%','K2s':'40-45%','Q5s':'40-45%','J7s':'40-45%','K4o':'40-45%','T8s':'40-45%','Q4s':'40-45%','Q7o':'40-45%','K3o':'40-45%','J8o':'40-45%','T9o':'40-45%',
